"use client";

import { ColumnDef } from "@tanstack/react-table";

// Generic row type
export type TableRow = Record<string, unknown>;

// Format value based on type
function formatValue(value: unknown): string {
  if (value === null || value === undefined) return "-";
  if (typeof value === "number") {
    // Check if it looks like a currency amount
    return value.toLocaleString();
  }
  if (typeof value === "boolean") return value ? "Yes" : "No";
  if (value instanceof Date) return value.toLocaleDateString();
  if (typeof value === "string") {
    // Check if it's an ISO date string
    if (/^\d{4}-\d{2}-\d{2}/.test(value)) {
      return new Date(value).toLocaleDateString();
    }
    return value;
  }
  return String(value);
}

// Convert field name to readable header
function formatHeader(field: string): string {
  return field
    .replace(/_/g, " ")
    .replace(/([A-Z])/g, " $1")
    .replace(/^./, (str) => str.toUpperCase())
    .trim();
}

// Status badge component for status-like fields
function StatusBadge({ status }: { status: string }) {
  const variants: Record<string, string> = {
    success: "bg-emerald-50 text-emerald-700 dark:bg-emerald-950 dark:text-emerald-300",
    completed: "bg-emerald-50 text-emerald-700 dark:bg-emerald-950 dark:text-emerald-300",
    active: "bg-emerald-50 text-emerald-700 dark:bg-emerald-950 dark:text-emerald-300",
    processing: "bg-amber-50 text-amber-700 dark:bg-amber-950 dark:text-amber-300",
    pending: "bg-amber-50 text-amber-700 dark:bg-amber-950 dark:text-amber-300",
    failed: "bg-red-50 text-red-700 dark:bg-red-950 dark:text-red-300",
    error: "bg-red-50 text-red-700 dark:bg-red-950 dark:text-red-300",
    cancelled: "bg-red-50 text-red-700 dark:bg-red-950 dark:text-red-300",
    inactive: "bg-zinc-100 text-zinc-700 dark:bg-zinc-800 dark:text-zinc-300",
  };

  const variant = variants[status.toLowerCase()] || "bg-zinc-100 text-zinc-700 dark:bg-zinc-800 dark:text-zinc-300";

  return (
    <span className={`inline-flex items-center rounded-md px-2 py-1 text-xs font-medium capitalize ${variant}`}>
      {status}
    </span>
  );
}

// Generate columns dynamically from field names
export function generateColumns(fields: string[]): ColumnDef<TableRow>[] {
  // Filter out common internal fields
  const displayFields = fields.filter(
    (f) => !["id", "created_at", "updated_at", "deleted_at"].includes(f)
  );

  return displayFields.map((field) => {
    const isStatusField = field.toLowerCase().includes("status") || field.toLowerCase() === "state";
    const isAmountField = field.toLowerCase().includes("amount") || field.toLowerCase().includes("price") || field.toLowerCase().includes("total");

    return {
      accessorKey: field,
      header: isAmountField
        ? () => <div className="text-right">{formatHeader(field)}</div>
        : formatHeader(field),
      cell: ({ row }) => {
        const value = row.getValue(field);

        // Status field - show badge
        if (isStatusField && typeof value === "string") {
          return <StatusBadge status={value} />;
        }

        // Amount field - right align and format as currency
        if (isAmountField && typeof value === "number") {
          return (
            <div className="text-right font-medium">
              {new Intl.NumberFormat("en-US", {
                style: "currency",
                currency: "USD",
              }).format(value)}
            </div>
          );
        }

        // Default formatting
        return <div className="text-muted-foreground">{formatValue(value)}</div>;
      },
    };
  });
}

// Default columns for demo (Payment type)
export type Payment = {
  id: string;
  email: string;
  amount: number;
  status: "success" | "processing" | "failed";
  created_at: string;
};

export const defaultColumns: ColumnDef<Payment>[] = [
  {
    accessorKey: "status",
    header: "Status",
    cell: ({ row }) => <StatusBadge status={row.getValue("status")} />,
  },
  {
    accessorKey: "email",
    header: "Email",
    cell: ({ row }) => <div className="text-muted-foreground">{row.getValue("email")}</div>,
  },
  {
    accessorKey: "amount",
    header: () => <div className="text-right">Amount</div>,
    cell: ({ row }) => (
      <div className="text-right font-medium">
        {new Intl.NumberFormat("en-US", {
          style: "currency",
          currency: "USD",
        }).format(row.getValue("amount"))}
      </div>
    ),
  },
];

"use client";

import { useMemo } from "react";
import { useRouter, useSearchParams } from "next/navigation";
import {
  flexRender,
  getCoreRowModel,
  useReactTable,
} from "@tanstack/react-table";
import { ChevronLeft, ChevronRight, ChevronsLeft, ChevronsRight } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { generateColumns, type TableRow as TRow } from "./columns";

interface DataTableProps {
  data: TRow[];
  fields: string[];
  pageCount?: number;
  pageIndex?: number;
  pageSize?: number;
}

export function DataTable({
  data,
  fields,
  pageCount = 1,
  pageIndex = 0,
  pageSize = 5,
}: DataTableProps) {
  const router = useRouter();
  const searchParams = useSearchParams();

  // Generate columns on the client side
  const columns = useMemo(() => generateColumns(fields), [fields]);

  const table = useReactTable({
    data,
    columns,
    pageCount,
    state: { pagination: { pageIndex, pageSize } },
    getCoreRowModel: getCoreRowModel(),
    manualPagination: true,
  });

  // Update URL search params and trigger server refetch
  const updatePagination = (newPage: number, newSize: number) => {
    const params = new URLSearchParams(searchParams.toString());
    params.set("page", newPage.toString());
    params.set("pageSize", newSize.toString());
    router.push(`?${params.toString()}`);
  };

  const handlePageChange = (newPage: number) => {
    updatePagination(newPage, pageSize);
  };

  const handlePageSizeChange = (newSize: number) => {
    updatePagination(0, newSize); // Reset to first page when changing page size
  };

  return (
    <div className="space-y-4">
      {/* Table */}
      <div className="rounded-md border">
        <Table>
          <TableHeader>
            {table.getHeaderGroups().map((headerGroup) => (
              <TableRow key={headerGroup.id}>
                {headerGroup.headers.map((header) => (
                  <TableHead key={header.id}>
                    {header.isPlaceholder ? null : flexRender(header.column.columnDef.header, header.getContext())}
                  </TableHead>
                ))}
              </TableRow>
            ))}
          </TableHeader>
          <TableBody>
            {table.getRowModel().rows?.length ? (
              table.getRowModel().rows.map((row) => (
                <TableRow key={row.id} data-state={row.getIsSelected() && "selected"}>
                  {row.getVisibleCells().map((cell) => (
                    <TableCell key={cell.id}>{flexRender(cell.column.columnDef.cell, cell.getContext())}</TableCell>
                  ))}
                </TableRow>
              ))
            ) : (
              <TableRow>
                <TableCell colSpan={columns.length} className="h-24 text-center">
                  No results.
                </TableCell>
              </TableRow>
            )}
          </TableBody>
        </Table>
      </div>

      {/* Pagination */}
      <div className="flex items-center justify-between px-2">
        <div className="flex items-center space-x-2">
          <p className="text-sm text-muted-foreground">Rows per page</p>
          <Select value={`${pageSize}`} onValueChange={(value) => handlePageSizeChange(Number(value))}>
            <SelectTrigger className="h-8 w-[70px]">
              <SelectValue placeholder={pageSize} />
            </SelectTrigger>
            <SelectContent side="top">
              {[5, 10, 20, 30, 50].map((size) => (
                <SelectItem key={size} value={`${size}`}>{size}</SelectItem>
              ))}
            </SelectContent>
          </Select>
        </div>
        <div className="flex items-center space-x-2">
          <p className="text-sm text-muted-foreground">
            Page {pageIndex + 1} of {pageCount}
          </p>
          <div className="flex items-center space-x-1">
            <Button variant="outline" size="icon" className="size-8" onClick={() => handlePageChange(0)} disabled={pageIndex === 0}>
              <ChevronsLeft className="size-4" />
            </Button>
            <Button variant="outline" size="icon" className="size-8" onClick={() => handlePageChange(pageIndex - 1)} disabled={pageIndex === 0}>
              <ChevronLeft className="size-4" />
            </Button>
            <Button variant="outline" size="icon" className="size-8" onClick={() => handlePageChange(pageIndex + 1)} disabled={pageIndex >= pageCount - 1}>
              <ChevronRight className="size-4" />
            </Button>
            <Button variant="outline" size="icon" className="size-8" onClick={() => handlePageChange(pageCount - 1)} disabled={pageIndex >= pageCount - 1}>
              <ChevronsRight className="size-4" />
            </Button>
          </div>
        </div>
      </div>
    </div>
  );
}

"use server";

import { createClient } from "@/lib/supabase/server";

export interface FetchDataOptions {
  tableName: string;
  fields?: string[];
  page?: number;
  pageSize?: number;
  orderBy?: string;
  orderAsc?: boolean;
}

export interface FetchDataResult<T = Record<string, unknown>> {
  data: T[];
  fields: string[];
  pageCount: number;
  totalCount: number;
  error?: string;
}

export async function fetchTableData<T = Record<string, unknown>>({
  tableName,
  fields,
  page = 0,
  pageSize = 5,
  orderBy = "created_at",
  orderAsc = false,
}: FetchDataOptions): Promise<FetchDataResult<T>> {
  try {
    const supabase = await createClient();
    if (!supabase) throw new Error("Supabase client not initialized");

    const from = page * pageSize;
    const to = from + pageSize - 1;

    // Build select string: specific fields or all (*)
    const selectFields = fields && fields.length > 0 ? fields.join(", ") : "*";

    // Get total count
    const { count, error: countError } = await supabase
      .from(tableName)
      .select("*", { count: "exact", head: true });

    if (countError) throw countError;

    const totalCount = count || 0;
    const pageCount = Math.ceil(totalCount / pageSize);

    // Get paginated data
    const { data, error: fetchError } = await supabase
      .from(tableName)
      .select(selectFields)
      .order(orderBy, { ascending: orderAsc })
      .range(from, to);

    if (fetchError) throw fetchError;

    // Extract field names from the first row if no fields specified
    const detectedFields = fields && fields.length > 0
      ? fields
      : data && data.length > 0
        ? Object.keys(data[0])
        : [];

    return {
      data: (data as T[]) || [],
      fields: detectedFields,
      pageCount,
      totalCount,
    };
  } catch (error) {
    return {
      data: [],
      fields: [],
      pageCount: 0,
      totalCount: 0,
      error: error instanceof Error ? error.message : "Failed to fetch data",
    };
  }
}
